You can animate a ball moving from one corner to another using the HTML `<canvas>` element and JavaScript. Here's a step-by-step guide with a working example:

### ✅ Step 1: Set up the HTML
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Animating a Ball on Canvas</title>
  <style>
    body {
      margin: 0;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      background: #f0f0f0;
    }
    canvas {
      border: 1px solid #000;
    }
  </style>
</head>
<body>
  <canvas id="gameCanvas" width="400" height="400"></canvas>

  <script>
    // Get the canvas and its 2D context
    const canvas = document.getElementById("gameCanvas");
    const ctx = canvas.getContext("2d");

    // Ball properties
    const ball = {
      x: 0,           // Start at top-left corner
      y: 0,
      radius: 20,
      speedX: 2,      // How fast it moves horizontally
      speedY: 1.5,    // How fast it moves vertically
      color: "red"
    };

    // Animation loop
    function animate() {
      // Clear the canvas
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw the ball
      ctx.beginPath();
      ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
      ctx.fillStyle = ball.color;
      ctx.fill();
      ctx.closePath();

      // Update position
      ball.x += ball.speedX;
      ball.y += ball.speedY;

      // Bounce off walls (reverse direction if hitting edge)
      if (ball.x + ball.radius > canvas.width || ball.x - ball.radius < 0) {
        ball.speedX = -ball.speedX;
      }
      if (ball.y + ball.radius > canvas.height || ball.y - ball.radius < 0) {
        ball.speedY = -ball.speedY;
      }

      // Continue animation
      requestAnimationFrame(animate);
    }

    // Start the animation
    animate();
  </script>
</body>
</html>
```

